def fibonacci(n):
    if n <= 0:
        return []
    elif n == 1:
        return [0]
    res = [0, 1]
    while len(res) < n:
        res.append(res[-1] + res[-2])
    return res

function getFib(num) {
  let a = 0, b = 1, temp;
  let arr = [0, 1];
  // wtf why is this breaking on 0
  if (num === 0) return [];
  if (num === 1) return [0];
  for(let i=2; i<num; i++){
    temp = a + b;
    a = b;
    b = temp;
    arr.push(temp);
  }
  return arr;
}
